import React from 'react';

const Home = () => {
    return (
        <div>
            <h2>Welcome to Teachable Machine</h2>
            <div style={{ display: 'flex', justifyContent: 'center', gap: '20px' }}>
                <div style={{ backgroundColor: 'green', color: 'white', padding: '40px', borderRadius: '10px', width: '200px' }}>
                    Image Project
                </div>
                <div style={{ backgroundColor: 'blue', color: 'white', padding: '40px', borderRadius: '10px', width: '200px' }}>
                    Audio Project
                </div>
                <div style={{ backgroundColor: 'red', color: 'white', padding: '40px', borderRadius: '10px', width: '200px' }}>
                    Pose Project
                </div>
            </div>
        </div>
    );
};

export default Home;
